// @vitest-environment jsdom
/**
 * @fileType test
 * @domain frontend
 * @pattern pdf-media, flexbox-layout
 * @ai-summary Tests for PDFMedia component rendering and CSS classes for proper flexbox containment
 */
import { PDFMedia } from '@/ui/web/media/PDFMedia'
import type { Media as MediaType } from '@/payload-types'
import { cleanup, render } from '@testing-library/react'
import { afterEach, describe, expect, it, vi } from 'vitest'

// Mock dependencies
vi.mock('@/infra/utils/ui', () => ({
  cn: vi.fn((...classes: (string | undefined)[]) => classes.filter(Boolean).join(' ')),
}))

vi.mock('@/infra/system-events', () => ({
  SYSTEM_EVENTS: {
    PDF_VIEWED: 'pdf-viewed',
  },
  systemEventBus: {
    emit: vi.fn(),
  },
}))

describe('PDFMedia component', () => {
  afterEach(() => {
    cleanup()
    vi.restoreAllMocks()
  })

  describe('iframe rendering', () => {
    it('should render iframe with PDF.js viewer URL when url is provided', () => {
      const mockMedia: MediaType = {
        id: 'test-id',
        tenant: 'test-tenant',
        type: 'document',
        retentionPolicy: 'persistent',
        updatedAt: '2024-01-01T00:00:00.000Z',
        createdAt: '2024-01-01T00:00:00.000Z',
        filename: 'test.pdf',
        url: 'https://example.blob.vercel-storage.com/test.pdf',
        mimeType: 'application/pdf',
      }

      const { container } = render(<PDFMedia resource={mockMedia} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeTruthy()
      expect(iframe?.getAttribute('src')).toContain('/api/pdfjs-viewer?file=')
      expect(iframe?.getAttribute('title')).toBe('PDF Viewer')
      expect(iframe?.getAttribute('class')).toContain('w-full')
      expect(iframe?.getAttribute('class')).toContain('h-full')
      expect(iframe?.getAttribute('class')).toContain('border-0')
    })

    it('should render iframe with relative URL when only filename is provided', () => {
      const mockMedia: MediaType = {
        id: 'test-id',
        tenant: 'test-tenant',
        type: 'document',
        retentionPolicy: 'persistent',
        updatedAt: '2024-01-01T00:00:00.000Z',
        createdAt: '2024-01-01T00:00:00.000Z',
        filename: 'my-document.pdf',
        mimeType: 'application/pdf',
      }

      const { container } = render(<PDFMedia resource={mockMedia} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeTruthy()
      expect(iframe?.getAttribute('src')).toContain('/api/pdfjs-viewer?file=')
      expect(iframe?.getAttribute('src')).toContain(encodeURIComponent('/media/my-document.pdf'))
    })
  })

  describe('wrapper classes for flex containment', () => {
    it('should have min-h-0 class on wrapper for flex containment', () => {
      const mockMedia: MediaType = {
        id: 'test-id',
        tenant: 'test-tenant',
        type: 'document',
        retentionPolicy: 'persistent',
        updatedAt: '2024-01-01T00:00:00.000Z',
        createdAt: '2024-01-01T00:00:00.000Z',
        filename: 'test.pdf',
        url: 'https://example.blob.vercel-storage.com/test.pdf',
        mimeType: 'application/pdf',
      }

      const { container } = render(<PDFMedia resource={mockMedia} />)

      const wrapper = container.querySelector('div')
      expect(wrapper).toBeTruthy()
      // Verify min-h-0 is present for proper flexbox containment
      expect(wrapper?.getAttribute('class')).toContain('min-h-0')
      // Verify other expected classes
      expect(wrapper?.getAttribute('class')).toContain('w-full')
      expect(wrapper?.getAttribute('class')).toContain('h-full')
    })

    it('should apply custom className alongside default classes', () => {
      const mockMedia: MediaType = {
        id: 'test-id',
        tenant: 'test-tenant',
        type: 'document',
        retentionPolicy: 'persistent',
        updatedAt: '2024-01-01T00:00:00.000Z',
        createdAt: '2024-01-01T00:00:00.000Z',
        filename: 'test.pdf',
        url: 'https://example.blob.vercel-storage.com/test.pdf',
        mimeType: 'application/pdf',
      }

      const { container } = render(<PDFMedia resource={mockMedia} className="custom-class" />)

      const wrapper = container.querySelector('div')
      expect(wrapper).toBeTruthy()
      expect(wrapper?.getAttribute('class')).toContain('custom-class')
    })
  })

  describe('null rendering', () => {
    it('should return null when resource is null', () => {
      const { container } = render(<PDFMedia resource={null} />)
      expect(container.firstChild).toBeNull()
    })

    it('should return null when resource is undefined', () => {
      const { container } = render(<PDFMedia resource={undefined} />)
      expect(container.firstChild).toBeNull()
    })

    it('should return null when resource has no url or filename', () => {
      const mockMedia = {
        id: 'test-id',
        tenant: 'test-tenant',
      }

      const { container } = render(<PDFMedia resource={mockMedia as unknown as MediaType} />)
      expect(container.firstChild).toBeNull()
    })

    it('should return null when resource is a string', () => {
      const { container } = render(<PDFMedia resource="not-an-object" />)
      expect(container.firstChild).toBeNull()
    })
  })

  describe('PDF.js viewer version parameter', () => {
    it('should include version parameter in viewer URL for cache busting', () => {
      const mockMedia: MediaType = {
        id: 'test-id',
        tenant: 'test-tenant',
        type: 'document',
        retentionPolicy: 'persistent',
        updatedAt: '2024-01-01T00:00:00.000Z',
        createdAt: '2024-01-01T00:00:00.000Z',
        filename: 'test.pdf',
        url: 'https://example.blob.vercel-storage.com/test.pdf',
        mimeType: 'application/pdf',
      }

      const { container } = render(<PDFMedia resource={mockMedia} />)

      const iframe = container.querySelector('iframe')
      expect(iframe?.getAttribute('src')).toContain('&v=4.4.168')
    })
  })
})

