/**
 * @fileType test
 * @domain frontend
 * @pattern pdf-rendering, flexbox-layout
 * @ai-summary Tests for PDF display in desktop layout - verifies min-h-0 classes for proper flexbox height propagation
 */

// @vitest-environment jsdom
import { describe, expect, it, vi } from 'vitest'
import { renderToStaticMarkup } from 'react/server'

// Mock the system events
vi.mock('@/infra/system-events', () => ({
  SYSTEM_EVENTS: { PDF_VIEWED: 'pdf-viewed' },
  systemEventBus: { emit: vi.fn() },
}))

// Mock the cn utility
vi.mock('@/infra/utils/ui', () => ({
  cn: (...classes: (string | undefined | null | false)[]) => classes.filter(Boolean).join(' '),
}))

// Mock useMediaQuery to return true for desktop in our tests
vi.mock('@/server/payload/hooks/useMediaQuery', () => ({
  useMediaQuery: vi.fn(() => true), // Desktop mode
}))

describe('PDF Desktop Layout Fix', () => {
  describe('PDFMedia component', () => {
    it('should render iframe with PDF.js viewer URL', async () => {
      // Import dynamically since PDFMedia is a client component
      const { PDFMedia } = await import('@/ui/web/media/PDFMedia')

      const mockResource = {
        id: 'test-pdf-1',
        filename: 'test.pdf',
        url: 'https://example.blob.vercel-storage.com/test.pdf',
        mimeType: 'application/pdf',
      }

      const result = renderToStaticMarkup(
        // @ts-expect-error - testing rendering
        <PDFMedia resource={mockResource} className="test-class" />,
      )

      // Verify iframe src contains PDF.js viewer URL
      expect(result).toContain('/api/pdfjs-viewer?file=')
      expect(result).toContain(
        encodeURIComponent('https://example.blob.vercel-storage.com/test.pdf'),
      )
      expect(result).toContain('title="PDF Viewer"')
    })

    it('should render wrapper with min-h-0 for flex containment', async () => {
      const { PDFMedia } = await import('@/ui/web/media/PDFMedia')

      const mockResource = {
        id: 'test-pdf-1',
        filename: 'test.pdf',
        url: '/media/test.pdf',
        mimeType: 'application/pdf',
      }

      const result = renderToStaticMarkup(
        // @ts-expect-error - testing rendering
        <PDFMedia resource={mockResource} />,
      )

      // Verify the wrapper div has min-h-0 for proper flexbox height propagation
      expect(result).toContain('min-h-0')
    })

    it('should render null when no URL available', async () => {
      const { PDFMedia } = await import('@/ui/web/media/PDFMedia')

      const mockResource = {
        id: 'test-pdf-1',
        filename: undefined,
        url: null,
      }

      const result = renderToStaticMarkup(
        // @ts-expect-error - testing rendering
        <PDFMedia resource={mockResource} />,
      )

      // Should render nothing when no PDF URL
      expect(result).toBe('')
